#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int minSalary[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &minSalary[i]);
        }
        int offeredSalary[M];
        int maxJobOffers[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &offeredSalary[i], &maxJobOffers[i]);
        }
        int qual[N][M];
        for (int i = 0; i < N; i++) {
            char str[M + 1];
            scanf("%s", str);
            for (int j = 0; j < M; j++) {
                qual[i][j] = str[j] - '0';
            }
        }
        int jobCount = 0;
        long long totalSalary = 0;
        int companyCount = 0;
        int jobOffers[M];
        for (int i = 0; i < M; i++) {
            jobOffers[i] = maxJobOffers[i];
        }
        for (int i = 0; i < N; i++) {
            int maxSalary = 0;
            int maxSalaryIndex = -1;
            for (int j = 0; j < M; j++) {
                if (qual[i][j] == 1 && jobOffers[j] > 0 && offeredSalary[j] >= minSalary[i] && offeredSalary[j] > maxSalary) {
                    maxSalary = offeredSalary[j];
                    maxSalaryIndex = j;
                }
            }
            if (maxSalaryIndex != -1) {
                jobCount++;
                totalSalary += maxSalary;
                jobOffers[maxSalaryIndex]--;
                if (jobOffers[maxSalaryIndex] == maxJobOffers[maxSalaryIndex] - 1) {
                    companyCount++;
                }
            }
        }
        int companyCountFinal = 0;
        for (int i = 0; i < M; i++) {
            if (jobOffers[i] == maxJobOffers[i]) {
                companyCountFinal++;
            }
        }
        printf("%d %lld %d\n", jobCount, totalSalary, companyCountFinal);
    }
    return 0;
}

